import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useParams, useNavigate } from 'react-router-dom';
import { Room, RoomEvent } from 'livekit-client';

const SimpleLiveKit: React.FC = () => {
  const { interviewId, agentId } = useParams<{ interviewId?: string; agentId?: string }>();
  const { state: authState } = useAuth();
  const navigate = useNavigate();

  const [messages, setMessages] = useState<string[]>([]);
  const [isConnected, setIsConnected] = useState(false);
  const [sessionStarted, setSessionStarted] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [micEnabled, setMicEnabled] = useState(false);

  const roomRef = useRef<Room | null>(null);
  const websocketRef = useRef<WebSocket | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);

  useEffect(() => {
    if (interviewId || agentId) {
      initializeSession();
    }
    return () => cleanup();
  }, [interviewId, agentId]);

  const initializeSession = async () => {
    const sessionId = interviewId || agentId;

    // Connect to WebSocket
    const wsUrl = `ws://localhost:8000/ws/${sessionId}`;
    websocketRef.current = new WebSocket(wsUrl);

    websocketRef.current.onopen = () => {
      console.log('WebSocket connected');
      setIsConnected(true);

      websocketRef.current?.send(JSON.stringify({
        type: 'join_session',
        participant_id: authState.user?.id,
        participant_name: `${authState.user?.first_name} ${authState.user?.last_name}`,
        role: 'student',
        session_type: agentId ? 'practice' : 'interview'
      }));
    };

    websocketRef.current.onmessage = (event) => {
      const data = JSON.parse(event.data);
      handleWebSocketMessage(data);
    };
  };

  const handleWebSocketMessage = (data: any) => {
    console.log('WebSocket message received:', data.type, data);

    switch (data.type) {
      case 'session_ready':
        console.log('Session ready:', data);
        setSessionStarted(true);
        if (data.livekit_info) {
          connectToLiveKit(data.livekit_info);
        }
        break;
      case 'ai_response':
        console.log('AI response:', data);
        setMessages(prev => [...prev, `AI: ${data.message}`]);
        break;
      case 'ai_audio':
        console.log('AI audio received, length:', data.audio_data?.length || 0);
        if (data.audio_data) {
          playAudioFromBase64(data.audio_data);
        } else {
          console.warn('No audio data in ai_audio message');
        }
        break;
      case 'transcript_update':
        console.log('Transcript update:', data);
        setMessages(prev => [...prev, `${data.entry.speaker}: ${data.entry.message}`]);
        break;
      case 'audio_processing':
        console.log('Audio processing status:', data.status, data.error || '');
        break;
    }
  };

  const connectToLiveKit = async (livekitInfo: any) => {
    try {
      console.log('Connecting to LiveKit...');

      const room = new Room();
      roomRef.current = room;

      // Connect to room
      await room.connect(livekitInfo.url, livekitInfo.token);

      // Enable microphone
      await room.localParticipant.setMicrophoneEnabled(true);
      setMicEnabled(true);

      // Start recording
      startRecording();

      console.log('LiveKit connected successfully');

    } catch (error) {
      console.error('LiveKit connection failed:', error);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.ondataavailable = async (event) => {
        if (event.data.size > 0) {
          const arrayBuffer = await event.data.arrayBuffer();
          const uint8Array = new Uint8Array(arrayBuffer);
          const base64Audio = btoa(String.fromCharCode.apply(null, Array.from(uint8Array)));

          console.log('Sending audio data:', { size: event.data.size, base64Length: base64Audio.length });

          websocketRef.current?.send(JSON.stringify({
            type: 'audio_data',
            audio_data: base64Audio, // Send as direct string, not nested object
            interview_id: interviewId || agentId
          }));
        }
      };

      mediaRecorder.start(2000);
      setIsRecording(true);

    } catch (error) {
      console.error('Recording failed:', error);
    }
  };

  const toggleMicrophone = async () => {
    if (!roomRef.current) return;

    try {
      if (micEnabled) {
        await roomRef.current.localParticipant.setMicrophoneEnabled(false);
        setMicEnabled(false);
      } else {
        await roomRef.current.localParticipant.setMicrophoneEnabled(true);
        setMicEnabled(true);
      }
    } catch (error) {
      console.error('Error toggling microphone:', error);
    }
  };

  const sendTextMessage = () => {
    const message = prompt('Enter your message:');
    if (message && websocketRef.current) {
      websocketRef.current.send(JSON.stringify({
        type: 'text_message',
        message: message
      }));
    }
  };

  const playAudioFromBase64 = (base64Audio: string) => {
    try {
      const audioData = atob(base64Audio);
      const audioArray = new Uint8Array(audioData.length);
      for (let i = 0; i < audioData.length; i++) {
        audioArray[i] = audioData.charCodeAt(i);
      }

      const audioBlob = new Blob([audioArray], { type: 'audio/wav' });
      const audioUrl = URL.createObjectURL(audioBlob);

      const audio = new Audio(audioUrl);
      audio.play().catch(error => {
        console.error('Error playing audio:', error);
      });

    } catch (error) {
      console.error('Error playing audio from base64:', error);
    }
  };

  const cleanup = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
    }
    if (roomRef.current) {
      roomRef.current.disconnect();
    }
    if (websocketRef.current) {
      websocketRef.current.close();
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-4xl mx-auto">
        <div className="bg-white rounded-lg shadow-sm p-6">
          <h1 className="text-2xl font-bold mb-4">LiveKit Voice Interview</h1>

          <div className="space-y-4">
            <div className="flex items-center space-x-4">
              <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`}></div>
              <span>{isConnected ? 'Connected' : 'Disconnected'}</span>
            </div>

            <div className="flex items-center space-x-4">
              <div className={`w-3 h-3 rounded-full ${isRecording ? 'bg-red-500 animate-pulse' : 'bg-gray-400'}`}></div>
              <span>{isRecording ? 'Recording' : 'Not Recording'}</span>
            </div>

            <div className="flex items-center space-x-4">
              <div className={`w-3 h-3 rounded-full ${micEnabled ? 'bg-green-500' : 'bg-red-500'}`}></div>
              <span>{micEnabled ? 'Mic On' : 'Mic Off'}</span>
            </div>

            <div className="space-x-4">
              <button
                onClick={toggleMicrophone}
                className={`px-4 py-2 rounded-lg font-medium ${
                  micEnabled 
                    ? 'bg-red-500 text-white hover:bg-red-600' 
                    : 'bg-green-500 text-white hover:bg-green-600'
                }`}
              >
                {micEnabled ? 'Disable Mic' : 'Enable Mic'}
              </button>
              <button
                onClick={sendTextMessage}
                className="bg-blue-500 text-white px-4 py-2 rounded-lg hover:bg-blue-600"
              >
                Send Text Message
              </button>
              <button
                onClick={() => navigate('/dashboard')}
                className="bg-gray-500 text-white px-4 py-2 rounded-lg hover:bg-gray-600"
              >
                End Session
              </button>
            </div>

            <div className="border rounded p-4 h-64 overflow-y-auto">
              {messages.map((msg, index) => (
                <div key={index} className="mb-2">{msg}</div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SimpleLiveKit;
